def build_prep_page(c, cfg):
    prep_page(c)

    # Header
    rgb(c, SPECIAL)
    c.rect(0, H - 40, W, 40, fill=1, stroke=0)
    rgb(c, WHITE)
    c.setFont(BF, 14)
    c.drawCentredString(W / 2, H - 26, f"CALLUM'S LEARNING PACK — {cfg['week_ref']}")
    c.setFont(TF, 9)
    c.drawCentredString(W / 2, H - 38, 'Adult preparation guide — print and laminate as instructed')

    y = H - 56

    # Session timetable
    rgb(c, DARK)
    c.setFont('Minecraftia', 10)
    c.drawString(MARGIN, y, 'Daily timetable')
    y -= 16

    timetable_rows = [
        ('9:30 – 9:40',   'Special Interest Time (A)',         'SIT card (laminate)',          SPECIAL),
        ('9:40 – 10:00',  'Being a Speller (with CM)',         'Speller page',                 SPELL),
        ('10:05 – 10:20', 'Being a Mathematician (independent)', 'Minecraft Maths page',        MATH_MC),
        ('10:30 – 10:45', 'Mastering Number (with CM)',        'Top half of combined sheet',   MATH_MN),
        ('11:00 – 11:15', 'Special Interest Time (B)',         'Same SIT card as (A)',         SPECIAL),
        ('13:15 – 13:30', 'Special Interest Time (C)',         'Same SIT card',                SPECIAL),
        ('13:30 – 13:45', 'Handwriting (1:2 with EJ)',         'Handwriting page',             HANDWRT),
        ('14:50 – 15:00', 'Maths/Writing Group (EJ)',          'Bottom half of combined sheet', MATH_MN),
    ]

    row_h = 16
    for time, session, resource, col in timetable_rows:
        if y < MARGIN + 10:
            break
        rgb(c, col)
        c.rect(MARGIN, y - row_h + 3, 5, row_h - 3, fill=1, stroke=0)
        rgb(c, DARK)
        c.setFont(TF, 8)
        c.drawString(MARGIN + 10, y - 8, time)
        c.setFont(TF, 8)
        c.drawString(MARGIN + 72, y - 8, session)
        rgb(c, MGREY)
        c.setFont(TF, 7.5)
        c.drawRightString(W - MARGIN, y - 8, resource)
        stroke(c, LGREY)
        c.setLineWidth(0.3)
        c.line(MARGIN, y - row_h + 2, W - MARGIN, y - row_h + 2)
        y -= row_h

    # Printing notes
    y -= 8
    rgb(c, DARK)
    c.setFont('Minecraftia', 10)
    c.drawString(MARGIN, y, 'Printing and prep notes')
    y -= 14

    notes = [
        'Print ALL pages single-sided on A4.',
        'Pages 2–6 (Monday): SIT card — laminate for reuse throughout the day.',
        'Combined sheet (Page D each day): cut along dotted line after printing.',
        'Bonus pages 27–31: print and keep as backup activities.',
        'CEW words this week: ' + ', '.join(cfg['cew_words']),
        'Maths topic: ' + cfg.get('maths_topic', 'as per class plan'),
    ]
    for note in notes:
        if y < MARGIN + 8:
            break
        c.setFont(TF, 8.5)
        rgb(c, DARK)
        c.drawString(MARGIN + 4, y, f'• {note}')
        y -= 13

    c.showPage()


# ─────────────────────────────────────────────────────────────────────────────
# MASTER BUILD
# ─────────────────────────────────────────────────────────────────────────────

def make_complete(cfg):
    out = f'/home/claude/Callum_{cfg["week_ref"]}_Complete.pdf'
    c   = rl_canvas.Canvas(out, pagesize=A4)

    # Page 1: prep guide
    build_prep_page(c, cfg)

    # Pages 2–26: 5 days × 5 pages
    for day_idx in range(5):
        build_sit(c, cfg, day_idx)
        build_speller(c, cfg, day_idx)
        build_mc_maths(c, cfg, day_idx)
        build_combined(c, cfg, day_idx)
        build_handwriting(c, cfg, day_idx)

    # Bonus pages 27–31
    build_pixel_art(c, cfg)
    build_maze(c, cfg)
    build_draw_world(c, cfg)
    build_design_grid(c, cfg)
    build_quiz(c, cfg)

    c.save()
    print(f'Done → {out}')
    return out


